+function _replaceRecur<TValue>(value: TValue, replacement: unknown): TValue {
+  const seen = new WeakMap<object, unknown>();
+  const replace = (current: unknown): unknown => {
+    if (current === Recur) return replacement;
+    if (Array.isArray(current)) return current.map(replace);
+    if (!current || typeof current !== 'object') return current;
+    if (current instanceof Map || current instanceof Set || current instanceof Date) {
+      return current;
+    }
+    const cached = seen.get(current);
+    if (cached) return cached;
+    const clone = Object.create(Object.getPrototypeOf(current));
+    seen.set(current, clone);
+    for (const key of Reflect.ownKeys(current)) {
+      const descriptor = Object.getOwnPropertyDescriptor(current, key);
+      if (descriptor?.value) descriptor.value = replace(descriptor.value);
+      Object.defineProperty(clone, key, descriptor!);
+    }
+    return clone;
+  };
+  return replace(value) as TValue;
